log_queries.query:
// Kubernetes RBAC privilege escalation detection
// Data source: Kubernetes audit logs ingested via Filebeat or Fluentd
event.dataset: "kubernetes.audit" AND 
  kubernetes.audit.objectRef.resource: ("clusterroles" OR "clusterrolebindings" OR "roles" OR "rolebindings") AND
  kubernetes.audit.verb: ("create" OR "update" OR "patch" OR "bind" OR "escalate" OR "impersonate") AND
  kubernetes.audit.responseStatus.code: (200 OR 201) AND
  NOT kubernetes.audit.user.username: (system\:kube-controller-manager OR system\:kube-scheduler OR system\:node\:*)
// Additional detection: ClusterRole with wildcard permissions
OR (
  event.dataset: "kubernetes.audit" AND
  kubernetes.audit.objectRef.resource: "clusterroles" AND
  kubernetes.audit.verb: ("create" OR "update" OR "patch") AND
  kubernetes.audit.requestObject.rules.verbs: "*"
)
// Additional detection: Impersonation attempts
OR (
  event.dataset: "kubernetes.audit" AND
  kubernetes.audit.impersonatedUser.username: * AND
  NOT kubernetes.audit.user.username: system\:kube-controller-manager
)

service:kubernetes-audit 
source:k8s.audit 
(
  @objectRef.resource:(clusterroles OR clusterrolebindings OR roles OR rolebindings) 
  @verb:(create OR update OR patch OR bind OR escalate OR impersonate)
  @responseStatus.code:(200 OR 201)
  -@user.username:(system\:kube-controller-manager OR system\:kube-scheduler OR system\:node\:*)
)
OR (
  @objectRef.resource:clusterroles
  @requestObject.rules.verbs:"*"
)
OR (
  @impersonatedUser.username:*
)
